function UserProfile({ user }) {
  return (
    <ProfileWrapper>
      <AvatarContainer>
        <Avatar src={user.avatarUrl} />
      </AvatarContainer>
      <InfoSection>
        <NameRow>
          <NameText>{user.name}</NameText>
        </NameRow>
        <EmailRow>
          <EmailText>{user.email}</EmailText>
        </EmailRow>
      </InfoSection>
    </ProfileWrapper>
  );
}

const ProfileWrapper = ({ children }) => <div className="profile">{children}</div>;
const AvatarContainer = ({ children }) => <div className="avatar-container">{children}</div>;
const InfoSection = ({ children }) => <section className="info">{children}</section>;
const NameRow = ({ children }) => <div className="name-row">{children}</div>;
const NameText = ({ children }) => <span className="name">{children}</span>;
const EmailRow = ({ children }) => <div className="email-row">{children}</div>;
const EmailText = ({ children }) => <span className="email">{children}</span>;
